INSERT INTO device_library_items (id, org_id, element_id, vendor, model, category, attributes, ndaa_compliant, specs) VALUES ('f08ada2d-b374-d9a0-faf1-c671084ada5b', NULL, 'e7b3b9cc-8cae-7738-35d5-292e73619905', 'TBD', 'Electrohydraulic 6400 series', 'access_control', '{"Descriptive Label":"The LCN 6400 COMPACT™ Series low-energy operator is a simple and cost-effective solution that enables facilities to automate more openings for touchless access and accessible operation. The modular design is unique and allows the reuse of an existing LCN 4040XP mechanical closer. The electrified module connects with a mounting plate and just four screws and drives open the mechanical closer. The simplicity of this solution reduces the cost, labor and complexity required to automate an opening.","Installation Status":"Proposed","Component Manufacturer":"TBD","Element Quantity":"1","Installation Hours":"1","Electrical Power":"24VDC","Link 1 Description":"Product Image","Link 1 Url":"https://us.allegion.com/content/dam/us-comm-mktg/Product_imagery/Door_controls/lcn_6400_series/LCN_6440_689_SR.jpg","Link 2 Description":"Installation Instructions","Link 2 Url":"https://us.allegion.com/content/dam/allegion-us-2/web-files/lcn/installation-documents/LCN_6400_Series_Compact_Installation_Instructions_113833.pdf"}'::jsonb, false, '{}'::jsonb) ON CONFLICT (id) DO UPDATE SET attributes = EXCLUDED.attributes, element_id = EXCLUDED.element_id;
